# Safe division
def safe_divide(a, b):
    try:
        result = a / b
        return result
    except ZeroDivisionError:
        return "Error: Can't divide by zero!"
    except TypeError:
        return "Error: Invalid types!"

print(safe_divide(10, 3))
print(safe_divide(10, 0))
print(safe_divide("10", 3))
